export default async function Users() {
    const users = await fetch("http://localhost:8080/users")
        .then((res) => res.json());
    return (
        <div>
            <h1>Users</h1>
            <ul>
                {users.map((user: any) => (
                    <li key={user.id}>
                        {user.name}
                        {user.email}
                    </li>
                ))}
            </ul>
        </div>
    );
}